-- Migrate customers.full_name to encrypted storage:
ALTER TABLE customers ADD COLUMN full_name_encrypted BYTEA;
UPDATE customers SET full_name_encrypted = pgp_sym_encrypt(full_name::TEXT, current_setting('app.encryption_key'));
ALTER TABLE customers DROP COLUMN full_name;
ALTER TABLE customers RENAME COLUMN full_name_encrypted TO full_name;

